       {/* Header */}
       <div className="p-4 flex items-center gap-4 bg-slate-900/90 backdrop-blur z-10 sticky top-0 border-b border-slate-800">
            <button onClick={() => setView('home')} className="p-2 hover:bg-white/10 rounded-full text-slate-400 hover:text-white transition-colors">
                <Icon name="arrow_back" />
            </button>
            <h2 className="text-xl font-bold">Configurações</h2>
        </div>

      <div className="flex-1 overflow-y-auto p-4 pb-24 space-y-6">

        {/* Profile */}
        <section>
             <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-2 block pl-1">Perfil</label>
             <div className="glass-panel rounded-xl p-4 space-y-4">
                <div>
                    <label className="text-xs text-slate-400 block mb-1">Como devo te chamar?</label>
                    <input
                        type="text"
                        className="w-full input-field p-3 rounded-lg text-sm"
                        value={settings.userName}
                        onChange={(e) => saveSettings({ ...settings, userName: e.target.value })}
                    />
                </div>
             </div>
        </section>

        {/* Feature Comparison Table */}
        <section>
            <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-2 block pl-1">Capacidades do Sistema</label>
            <div className="glass-panel rounded-xl overflow-hidden">
                <div className="grid grid-cols-3 bg-slate-800/50 p-3 text-xs font-semibold text-slate-400 border-b border-white/5">
                    <div className="col-span-1">Recurso</div>
                    <div className="text-center">Sem IA</div>
                    <div className="text-center text-blue-400">Com IA</div>
                </div>
                <div className="p-3 text-xs space-y-3">
                    <div className="grid grid-cols-3 items-center">
                        <span className="text-slate-300">Salvar Notas</span>
                        <span className="text-center text-green-500">✓</span>
                        <span className="text-center text-green-500">✓</span>
                    </div>
                     <div className="grid grid-cols-3 items-center">
                        <span className="text-slate-300">Busca Inteligente</span>
                        <span className="text-center text-slate-600">Manual</span>
                        <span className="text-center text-green-500">Semântica</span>
                    </div>
                     <div className="grid grid-cols-3 items-center">
                        <span className="text-slate-300">Resumo Automático</span>
                        <span className="text-center text-red-500/50">✕</span>
                        <span className="text-center text-green-500">✓</span>
                    </div>
                </div>
            </div>
        </section>

        {/* API Key Section */}
        <section>
            <div className="flex justify-between items-center mb-2 pl-1">
                <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Inteligência Artificial</label>
            </div>
            <div className="glass-panel rounded-xl p-4 border border-blue-500/10">
                <div className="flex items-start gap-3 mb-4">
                    <div className="p-2 bg-blue-600/20 rounded-lg text-blue-400">
                        <Icon name="smart_toy" />
                    </div>
                    <div>
                        <h3 className="font-semibold text-sm">Chave de Acesso (API Key)</h3>
                        <p className="text-xs text-slate-400 mt-1">Necessário para recursos Premium.</p>
                    </div>
                </div>
                <input
                    type="password"
                    placeholder="Cole sua chave Google Gemini aqui"
                    className="w-full input-field p-3 rounded-lg text-sm mb-3"
                    value={settings.apiKey}
                    onChange={(e) => saveSettings({ ...settings, apiKey: e.target.value })}
                />

                <div className="bg-slate-950/50 rounded-lg p-3">
                    <p className="text-[10px] text-slate-400 mb-2">
                        Não tem uma chave? O Google oferece uma cota gratuita generosa para uso pessoal.
                    </p>
                    <a href="https://aistudio.google.com/app/apikey" target="_blank" className="flex items-center justify-center w-full py-2 bg-slate-800 hover:bg-slate-700 rounded text-xs text-blue-300 transition-colors gap-1">
                        Ver tabela de preços e gerar chave <Icon name="open_in_new" size={12} />
                    </a>
                </div>
            </div>
        </section>

        {/* Activation Mode */}
        <section>
             <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-2 block pl-1">Ativação</label>
             <div className="glass-panel rounded-xl p-4">
                <div className="flex items-center justify-between mb-4">
                    <span className="text-sm">Modo de Abertura</span>
                    <div className="flex bg-slate-800 rounded-lg p-1">
                        <button 
                            onClick={() => saveSettings({...settings, activationMode: 'touch'})}
                            className={`px-3 py-1 rounded text-xs ${settings.activationMode === 'touch' ? 'bg-slate-600 text-white' : 'text-slate-500'}`}
                        >Toque</button>
                        <button 
                            onClick={() => saveSettings({...settings, activationMode: 'voice'})}
                            className={`px-3 py-1 rounded text-xs ${settings.activationMode === 'voice' ? 'bg-slate-600 text-white' : 'text-slate-500'}`}
                        >Voz</button>
                    </div>
                </div>
                {settings.activationMode === 'voice' && (
                    <div>
                        <label className="text-xs text-slate-400 block mb-1">Palavra de ativação</label>
                        <input
                            type="text"
                            className="w-full input-field p-3 rounded-lg text-sm"
                            value={settings.triggerWord}
                            onChange={(e) => saveSettings({ ...settings, triggerWord: e.target.value })}
                        />
                        <p className="text-[10px] text-yellow-500 mt-2 flex items-center gap-1">
                            <Icon name="warning" size={12} /> O modo voz consome mais bateria.
                        </p>
                    </div>
                )}
             </div>
        </section>

        {/* Backup */}
        <section>
             <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-2 block pl-1">Segurança de Dados</label>
             <div className="glass-panel rounded-xl p-4">
                 <p className="text-xs text-slate-300 mb-4">
                    O ExoMind segue o conceito <strong>Local-First</strong>. Seus dados estão neste aparelho. O backup em nuvem é opcional, mas recomendado para evitar perda de dados.
                 </p>
                 <div className="flex items-center justify-between mb-2">
                    <span className="text-sm">Frequência de Backup</span>
                    <select 
                        className="bg-slate-800 border-none text-xs text-white rounded p-1"
                        value={settings.backupFrequency}
                        onChange={(e) => saveSettings({...settings, backupFrequency: e.target.value as any})}
                    >
                        <option value="daily">Diário</option>
                        <option value="weekly">Semanal</option>
                        <option value="manual">Manual</option>
                    </select>
                 </div>
                 <button className="w-full py-3 border border-slate-600 rounded-lg text-xs text-slate-400 hover:text-white hover:border-slate-400 transition-colors flex items-center justify-center gap-2">
                    <Icon name="cloud_off" size={16} /> Configurar Provedor de Nuvem (Opcional)
                 </button>
             </div>
        </section>

        <button onClick={handleInstallClick} className="w-full py-4 text-slate-500 text-xs hover:text-white transition-colors">
            Instalar atalho na tela inicial
        </button>

      </div>
    </div>
  );

  const renderHome = () => (
    <div className="flex flex-col h-full relative animate-fadeIn">
      {/* Top Bar with Status Card */}
      <div className="p-4 pt-6 bg-gradient-to-b from-slate-900 via-slate-900/95 to-transparent z-10">
         <div className="flex justify-between items-start mb-4">
            <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-full bg-slate-800 flex items-center justify-center border border-slate-700">
                    <Icon name="face" className="text-slate-400" />
                </div>
                <div>
                    <h1 className="text-sm font-bold text-slate-200">Olá, {settings.userName}</h1>
                    <div className="flex items-center gap-2">
                        <span className={`w-1.5 h-1.5 rounded-full ${settings.apiKey ? 'bg-green-500 shadow-[0_0_8px_rgba(34,197,94,0.6)]' : 'bg-yellow-500'}`}></span>
                        <span className="text-[10px] text-slate-400 uppercase tracking-wider">
                            {settings.apiKey ? 'Online (IA Ativa)' : 'Offline (Modo Básico)'}
                        </span>
                    </div>
                </div>
            </div>
            <button onClick={handleExit} className="p-2 bg-slate-800/50 rounded-full text-red-400 hover:bg-red-500 hover:text-white transition-all">
                <Icon name="power_settings_new" size={20} />
            </button>
         </div>

         {/* Mini Dashboard / Summary */}
         {!settings.apiKey && (
             <div onClick={() => setView('settings')} className="bg-yellow-900/20 border border-yellow-500/20 p-3 rounded-lg flex justify-between items-center cursor-pointer mb-2">
                <div className="flex items-center gap-2">
                    <Icon name="info" size={16} className="text-yellow-500" />
                    <span className="text-xs text-yellow-200">IA não configurada. Recursos limitados.</span>
                </div>
                <Icon name="chevron_right" size={16} className="text-yellow-500" />
             </div>
         )}
      </div>

      {/* Main Content */}
      <div className="flex-1 flex flex-col items-center justify-center text-center opacity-80 px-6 relative">
         {/* Background Effect */}
         <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
             <div className="w-64 h-64 bg-blue-600/5 rounded-full blur-3xl"></div>
         </div>

        {memories.length === 0 ? (
           <div className="z-10">
            <button 
                onClick={() => settings.activationMode === 'voice' ? alert("Escutando...") : document.getElementById('mainInput')?.focus()}
                className="w-20 h-20 bg-slate-800 rounded-full flex items-center justify-center mb-6 mx-auto shadow-xl shadow-black/40 hover:scale-105 transition-transform border border-slate-700"
            >
                <Icon name={settings.activationMode === 'voice' ? 'mic' : 'keyboard'} size={32} className="text-blue-400" />
            </button>
            <h3 className="text-lg font-medium text-slate-200 mb-2">Estou pronto.</h3>
            <p className="text-slate-500 text-sm max-w-xs mx-auto">
                {settings.activationMode === 'voice' 
                    ? `Diga "${settings.triggerWord}" para começar.` 
                    : "Toque no botão abaixo ou digite para salvar uma memória."}
            </p>
           </div>
        ) : (
            <div className="w-full max-w-md space-y-3 overflow-y-auto max-h-[50vh] pr-2 z-10">
                <div className="flex justify-between items-center px-1 mb-2">
                    <span className="text-xs text-slate-500 uppercase tracking-wider font-bold">Recentes</span>
                    <button onClick={() => setView('history')} className="text-xs text-blue-400">Ver todas</button>
                </div>
                {memories.slice(0, 3).map(mem => (
                    <div key={mem.id} className="glass-panel p-4 rounded-xl text-left border-l-2 border-blue-500/50">
                        <p className="text-sm truncate text-slate-200">{mem.content}</p>
                        <div className="flex justify-between mt-2">
                             <span className="text-[10px] text-slate-500">{new Date(mem.timestamp).toLocaleDateString()}</span>
                             <span className="text-[10px] text-slate-600 bg-slate-800 px-2 rounded-full">{mem.tags[0]}</span>
                        </div>
                    </div>
                ))}
            </div>
        )}
      </div>

      {/* Input Area */}
      <div className="p-4 pb-6 bg-slate-900">
        <div className="glass-panel p-2 rounded-2xl flex items-center gap-2 shadow-2xl shadow-black/50 border border-slate-700">
          <button onClick={() => requestAIAction(() => alert("Câmera"))} className="p-3 text-slate-400 hover:text-white rounded-xl hover:bg-white/10 transition-colors">
            <Icon name="add_a_photo" />
          </button>
          <input 
            id="mainInput"
            type="text" 
            placeholder="Salvar nova memória..."
            className="flex-1 bg-transparent border-none outline-none text-white placeholder-slate-500 text-sm"
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSaveMemory()}
          />
          {inputText ? (
             <button 
                onClick={handleSaveMemory}
                className="p-3 bg-blue-600 text-white rounded-xl shadow-lg shadow-blue-500/20"
             >
                <Icon name="send" />
             </button>
          ) : (
            <button 
                onClick={() => saveSettings({ ...settings, activationMode: settings.activationMode === 'voice' ? 'touch' : 'voice' })}
                className={`p-3 rounded-xl transition-all ${settings.activationMode === 'voice' ? 'bg-red-500/20 text-red-400' : 'text-slate-400'}`}
            >
                <Icon name="mic" />
            </button>
          )}
        </div>
      </div>
    </div>
  );

  const renderHistory = () => (
      <div className="flex flex-col h-full bg-slate-900 animate-fadeIn">
        <div className="p-4 flex items-center gap-4 border-b border-slate-800 bg-slate-900/95 sticky top-0 z-10">
            <button onClick={() => setView('home')} className="p-2 hover:bg-white/10 rounded-full text-slate-400 hover:text-white">
                <Icon name="arrow_back" />
            </button>
            <h2 className="text-xl font-bold">Memórias</h2>
        </div>

        <div className="p-4">
             <div className="flex gap-2 mb-4 overflow-x-auto pb-2 no-scrollbar">
                <button className="px-4 py-2 bg-blue-600 text-white text-xs rounded-full whitespace-nowrap">Todas</button>
                <button onClick={() => requestAIAction(() => {})} className="px-4 py-2 bg-slate-800 text-slate-400 text-xs rounded-full whitespace-nowrap border border-slate-700 flex items-center gap-1">
                    <Icon name="smart_toy" size={14} /> Geradas por IA
                </button>
                <button className="px-4 py-2 bg-slate-800 text-slate-400 text-xs rounded-full whitespace-nowrap border border-slate-700">Imagens</button>
             </div>

            <input 
                type="text" 
                placeholder="Buscar nas memórias..." 
                className="w-full input-field p-3 rounded-xl mb-6 text-sm"
                onChange={() => !settings.apiKey && requestAIAction(() => {})} // Mocking search limit
            />

            <div className="space-y-4 pb-24">
                {memories.map(memory => (
                    <div key={memory.id} className="glass-panel p-4 rounded-xl border-l-4 border-l-blue-500/50 hover:border-l-blue-500 transition-colors">
                        <div className="flex justify-between items-start mb-2">
                            <span className="text-[10px] bg-slate-800 px-2 py-1 rounded text-slate-400 uppercase tracking-wide">
                                {memory.type}
                            </span>
                            <span className="text-xs text-slate-500">
                                {new Date(memory.timestamp).toLocaleDateString()}
                            </span>
                        </div>
                        <p className="text-slate-200 mb-3 text-sm leading-relaxed">{memory.content}</p>
                        <div className="pt-3 border-t border-white/5 flex justify-between items-center">
                             <div className="text-[10px] text-slate-500 flex gap-2">
                                {memory.tags.map(t => <span key={t}>#{t}</span>)}
                             </div>
                             {memory.aiSummary && (
                                <Icon name={memory.aiSummary.includes('Sem IA') ? 'cloud_off' : 'auto_awesome'} size={14} className="text-slate-600" />
                             )}
                        </div>
                    </div>
                ))}
            </div>
        </div>
      </div>
  );

  // --- Bottom Navigation ---

  const BottomNav = () => {
    if (view === 'onboarding' || view === 'splash') return null;
    return (
        <div className="fixed bottom-0 left-0 w-full glass-panel border-t border-slate-700 pb-safe pt-2 px-6 flex justify-between items-center z-50 rounded-t-2xl">
            <button 
                onClick={() => setView('home')}
                className={`p-4 flex flex-col items-center gap-1 transition-colors ${view === 'home' ? 'text-blue-400' : 'text-slate-500'}`}
            >
                <Icon name="home" />
                <span className="text-[10px] font-medium">Início</span>
            </button>
            <button 
                 onClick={() => setView('history')}
                className={`p-4 flex flex-col items-center gap-1 transition-colors ${view === 'history' ? 'text-blue-400' : 'text-slate-500'}`}
            >
                <Icon name="history" />
                <span className="text-[10px] font-medium">Memória</span>
            </button>
             <button 
                onClick={() => setView('settings')}
                className={`p-4 flex flex-col items-center gap-1 transition-colors ${view === 'settings' ? 'text-blue-400' : 'text-slate-500'}`}
            >
                <Icon name="tune" />
                <span className="text-[10px] font-medium">Ajustes</span>
            </button>
        </div>
    )
  }

  return (
    <div className="min-h-screen bg-slate-950 text-slate-200 overflow-hidden font-sans selection:bg-blue-500/30">
      <div className="max-w-md mx-auto h-screen flex flex-col relative shadow-2xl bg-slate-900">
        <main className="flex-1 overflow-y-auto no-scrollbar">
            {view === 'splash' && renderSplash()}
            {view === 'onboarding' && renderOnboarding()}
            {view === 'settings' && renderSettings()}
            {view === 'home' && renderHome()}
            {view === 'history' && renderHistory()}
        </main>
        <BottomNav />
        {showGateModal && <FeatureGateModal onClose={() => setShowGateModal(false)} onGoToSettings={() => { setShowGateModal(false); setView('settings'); }} />}
      </div>
    </div>
  );
};

const root = createRoot(document.getElementById('root')!);
root.render(<App />);
